  };

  const startBatchExport = async () => {
    if (!carousel || !canvasRef.current || isExporting || selectedSlidesToExport.size === 0) return;
    setShowExportModal(false);
    const originalIndex = currentIndex;
    const exportIndices = Array.from(selectedSlidesToExport).sort((a, b) => Number(a) - Number(b));
    const images: { name: string; dataUrl: string }[] = [];
    setIsExporting(true);
    try {
      const total = exportIndices.length;
      for (let i = 0; i < total; i++) {
        const slideIdx = exportIndices[i];
        setExportStatus(`Processando: ${i + 1} de ${total}`);
        setExportProgress(Math.round(((i + 1) / total) * 100));
        setCurrentIndex(slideIdx);
        await new Promise(resolve => setTimeout(resolve, 850));
        const dataUrl = await captureJpeg(canvasRef.current);
        images.push({ name: `slide-${(i + 1).toString().padStart(2, '0')}.jpg`, dataUrl });
      }
      setExportStatus('Finalizando ZIP...');
      // Now including the project JSON data for re-import capability
      await downloadZip(images, `carousel-${Date.now()}.zip`, dslInput);
      setExportStatus('Exportação concluída!');
      setTimeout(() => {
        setIsExporting(false);
        setExportProgress(0);
        setCurrentIndex(originalIndex);
      }, 1500);
    } catch (err) {
      setError('Erro na exportação.');
      setIsExporting(false);
      setCurrentIndex(originalIndex);
    }
  };

  const handleApplyPalettePreset = (preset: any) => {
    setActivePaletteId(preset.id);
    const defaults = preset.defaults || {
      bg: preset.colors[0],
      accent: preset.colors[2],
      text: preset.colors[1],
      cardBg: preset.colors[2]
    };
    updateSlideProperties([
      { path: ['options', 'background'], value: defaults.bg },
      { path: ['options', 'accent'], value: defaults.accent },
      { path: ['options', 'text'], value: defaults.text },
      { path: ['options', 'cardBg'], value: defaults.cardBg }
    ]);
  };

  const handleCreatePalette = () => {
    if (!newPaletteData.name.trim()) return;
    setIsSyncing(true);
    const newPreset = {
      id: `lp_${Date.now()}`,
      name: newPaletteData.name,
      colors: newPaletteData.colors,
      defaults: {
        bg: newPaletteData.colors[0],
        accent: newPaletteData.colors[2],
        text: newPaletteData.colors[1],
        cardBg: newPaletteData.colors[2]
      }
    };

    try {
      const localPalettes = JSON.parse(localStorage.getItem(STORAGE_KEYS.PALETTES) || '[]');
      localStorage.setItem(STORAGE_KEYS.PALETTES, JSON.stringify([...localPalettes, newPreset]));
      showToast("Paleta salva localmente.");
    } catch (err: any) {
      console.error(err);
      showToast("Erro ao salvar paleta.", "error");
    } finally {
      setIsCreatingPalette(false);
      setNewPaletteData({ name: '', colors: ['#0D0D0D', '#FFFFFF', '#EAB308', '#EAB308', '#EAB308'] });
      loadData();
      setIsSyncing(false);
    }
  };

  const handleDeletePalette = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (DEFAULT_BRAND_PRESETS.some(d => d.id === id)) return;
    setIsSyncing(true);
    try {
      const localPalettes = JSON.parse(localStorage.getItem(STORAGE_KEYS.PALETTES) || '[]');
      const filtered = localPalettes.filter((p: any) => p.id !== id);
      localStorage.setItem(STORAGE_KEYS.PALETTES, JSON.stringify(filtered));
      showToast("Paleta removida.");
      loadData();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsSyncing(false);
    }
  };

  const handleTemplateSelect = (tpl: TemplateDefinition) => {
    const updates: { path: (string | number)[], value: any }[] = [
      { path: ['template'], value: tpl.name }
    ];

    switch(tpl.name) {
      case 'PREMIUM_GLASS':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_GLASS_CARD' });
        updates.push({ path: ['image', 'boxOverlay'], value: 'dark' });
        break;
      case 'SPLIT_EDITORIAL':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_SPLIT_HALF' });
        updates.push({ path: ['image', 'position'], value: 'right' });
        break;
      case 'PROFILE_FOCUS':
        updates.push({ path: ['image', 'type'], value: 'FOCUS_SUBJECT' });
        updates.push({ path: ['image', 'position'], value: 'right' });
        break;
      case 'FOCUS_OBJECT':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_BOX' });
        updates.push({ path: ['image', 'position'], value: 'right' });
        updates.push({ path: ['image', 'width'], value: 600 });
        break;
      case 'CINEMATIC_BG':
      case 'HERO_STATEMENT':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_BACKGROUND' });
        updates.push({ path: ['image', 'overlay'], value: 'dark' });
        break;
      case 'IMAGE_SIDEBAR':
        updates.push({ path: ['image', 'type'], value: 'IMAGE_BOX' });
        updates.push({ path: ['image', 'position'], value: 'right' });
        updates.push({ path: ['image', 'width'], value: 400 });
        break;
      case 'CARD_BOX':
      case 'INFO_LIST_V1':
      case 'CARD_CLUSTER':
        if (!imageConfig?.url) {
           updates.push({ path: ['image', 'type'], value: 'NONE' });
        }
        break;
    }

    updateSlideProperties(updates);
    showToast(`Template ${tpl.name.replace(/_/g, ' ')} aplicado!`, "success");
  };

  const clients = useMemo(() => {
    const set = new Set(projects.map(p => p.client_name));
    return Array.from(set).sort();
  }, [projects]);

  const filteredProjects = useMemo(() => {
    return projects.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase()) || p.client_name.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesClient = selectedClientFilter ? p.client_name === selectedClientFilter : true;
      return matchesSearch && matchesClient;
    });
  }, [projects, searchQuery, selectedClientFilter]);

  return (
    <div className="flex h-screen w-full bg-[#050507] text-zinc-300 font-sans overflow-hidden">

      {/* Feedback Toast */}
      {toast && (
        <div className={`fixed bottom-12 left-1/2 -translate-x-1/2 z-[9999] px-12 py-6 rounded-[32px] flex items-center gap-6 animate-in slide-in-from-bottom-12 fade-in duration-500 shadow-[0_30px_90px_rgba(0,0,0,0.6)] backdrop-blur-3xl border border-white/10 ${toast.type === 'success' ? 'bg-emerald-500/95 text-black' : 'bg-red-500/95 text-white'}`}>
          {toast.type === 'success' ? <CheckCircle size={28} strokeWidth={3} /> : <AlertCircle size={28} strokeWidth={3} />}
          <span className="text-[16px] font-black uppercase tracking-[0.1em]">{toast.message}</span>
        </div>
      )}

      {/* OVERLAYS & MODALS */}
      {toolbarState && (
        <FloatingTextToolbar state={toolbarState} onClose={() => setToolbarState(null)} onUpdate={updateSlideProperties} />
      )}

      {/* Export Modal UI */}
      {showExportModal && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => setShowExportModal(false)}>
           <div className="w-full max-w-2xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Exportar Carrossel</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">ZIP conterá imagens + arquivo de configuração do projeto</p>
                 </div>
                 <button onClick={() => setShowExportModal(false)} className="p-3 hover:bg-white/5 rounded-full text-zinc-500 transition-colors"><X size={24}/></button>
              </div>

              <div className="grid grid-cols-4 gap-4 max-h-[400px] overflow-y-auto custom-scrollbar p-1">
                 {carousel?.slides.map((s, idx) => (
                    <button 
                      key={idx}
                      onClick={() => {
                        const next = new Set(selectedSlidesToExport);
                        if (next.has(idx)) next.delete(idx);
                        else next.add(idx);
                        setSelectedSlidesToExport(next);
                      }}
                      className={`relative aspect-[4/5] rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-3 overflow-hidden ${selectedSlidesToExport.has(idx) ? 'border-emerald-500 bg-emerald-500/10' : 'border-white/5 bg-black/40 hover:border-white/20'}`}
                    >
                       <div className={`w-10 h-10 rounded-full flex items-center justify-center ${selectedSlidesToExport.has(idx) ? 'bg-emerald-500 text-black' : 'bg-zinc-800 text-zinc-500'}`}>
                          <span className="font-black text-xs">{idx + 1}</span>
                       </div>
                       <p className="text-[10px] font-black uppercase text-zinc-500 tracking-widest truncate px-2 w-full">{s.template.replace(/_/g, ' ')}</p>
                       {selectedSlidesToExport.has(idx) && (
                         <div className="absolute top-2 right-2 text-emerald-500"><CheckCircle2 size={16} /></div>
                       )}
                    </button>
                 ))}
              </div>

              <div className="flex gap-4 pt-4 border-t border-white/5">
                 <button onClick={() => setSelectedSlidesToExport(new Set())} className="px-6 py-5 text-[10px] font-black text-zinc-500 uppercase tracking-widest hover:text-white transition-all">Limpar Tudo</button>
                 <button onClick={() => setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i)))} className="px-6 py-5 text-[10px] font-black text-emerald-500 uppercase tracking-widest hover:text-emerald-400 transition-all">Selecionar Todos</button>
                 <button onClick={startBatchExport} disabled={selectedSlidesToExport.size === 0} className="flex-1 py-5 bg-emerald-500 hover:bg-emerald-400 disabled:opacity-30 text-black font-black uppercase rounded-2xl shadow-xl transition-all flex items-center justify-center gap-3">
                    <Download size={18} strokeWidth={3} /> Gerar {selectedSlidesToExport.size} Slides
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* Icon Selector Modal UI */}
      {editingIconBlock && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => setEditingIconBlock(null)}>
           <div className="w-full max-w-2xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Escolher Ícone</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">Biblioteca de símbolos premium</p>
                 </div>
                 <button onClick={() => setEditingIconBlock(null)} className="p-3 hover:bg-white/5 rounded-full text-zinc-500"><X size={24}/></button>
              </div>

              <div className="grid grid-cols-4 sm:grid-cols-6 gap-4 p-1">
                 {ICON_LIBRARY_PRESETS.map(item => (
                    <button 
                      key={item.id}
                      onClick={() => {
                        updateSlideProperty(['blocks', editingIconBlock.index, 'options', 'icon'], item.id);
                        setEditingIconBlock(null);
                      }}
                      className={`flex flex-col items-center justify-center gap-3 p-5 rounded-3xl border-2 transition-all group ${editingIconBlock.block.options?.icon === item.id ? 'border-emerald-500 bg-emerald-500/10 text-emerald-400' : 'border-white/5 bg-black/40 hover:border-emerald-500/50'}`}
                    >
                       <item.icon size={32} strokeWidth={1.5} className="transition-transform group-hover:scale-110" />
                       <span className="text-[8px] font-black uppercase tracking-tighter text-zinc-600 group-hover:text-emerald-500">{item.label}</span>
                    </button>
                 ))}
              </div>

              <div className="space-y-3">
                 <label className="text-[9px] font-black uppercase text-zinc-500 px-1 tracking-widest">Personalizado (Lucide Name ou URL)</label>
                 <div className="flex gap-3">
                    <input 
                      type="text" 
                      placeholder="Ex: Rocket, https://..." 
                      className="flex-1 bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm font-bold text-white outline-none focus:border-emerald-500/50 transition-all"
                      value={iconInput}
                      onChange={(e) => setIconInput(e.target.value)}
                    />
                    <button 
                      onClick={() => {
                        updateSlideProperty(['blocks', editingIconBlock.index, 'options', 'icon'], iconInput);
                        setEditingIconBlock(null);
                      }}
                      className="px-8 py-4 bg-zinc-800 text-white font-black uppercase text-[10px] rounded-2xl hover:bg-zinc-700 transition-all"
                    >
                      Aplicar
                    </button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {/* Palette Creation Modal */}
      {isCreatingPalette && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => setIsCreatingPalette(false)}>
           <div className="w-full max-w-xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Nova Identidade Visual</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">Defina as cores da marca</p>
                 </div>
                 <button onClick={() => setIsCreatingPalette(false)} className="p-3 hover:bg-white/5 rounded-full text-zinc-500"><X size={24}/></button>
              </div>
              <div className="space-y-8">
                <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase text-zinc-500 px-1 tracking-widest">Nome da Paleta / Marca</label>
                  <input type="text" value={newPaletteData.name} onChange={(e) => setNewPaletteData({ ...newPaletteData, name: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-5 px-6 text-base text-white font-bold outline-none focus:border-emerald-500/50 transition-all" placeholder="Ex: Apple Minimal" />
                </div>
                <div className="grid grid-cols-5 gap-4">
                   {['Fundo', 'Texto', 'Acento', 'Destaque', 'Cards'].map((label, idx) => (
                     <div key={idx} className="flex flex-col items-center gap-3">
                        <span className="text-[9px] font-black uppercase text-zinc-600 tracking-tighter">{label}</span>
                        <div className="relative w-16 h-16 rounded-full overflow-hidden border-2 border-white/10 shadow-2xl group cursor-pointer ring-offset-4 ring-offset-zinc-900 focus-within:ring-2 ring-emerald-500 transition-all">
                           <input 
                              type="color" 
                              value={newPaletteData.colors[idx]} 
                              onChange={(e) => {
                                const nextColors = [...newPaletteData.colors];
                                nextColors[idx] = e.target.value;
                                setNewPaletteData({ ...newPaletteData, colors: nextColors });
                              }}
                              className="absolute inset-[-10px] w-[150%] h-[150%] cursor-pointer p-0 m-0 border-none bg-transparent" 
                           />
                           <div className="absolute inset-0 pointer-events-none flex items-center justify-center opacity-0 group-hover:opacity-100 bg-black/20 transition-opacity">
                              <Pipette size={16} className="text-white" />
                           </div>
                        </div>
                     </div>
                   ))}
                </div>
              </div>
              <div className="flex gap-4 pt-4">
                 <button onClick={() => setIsCreatingPalette(false)} className="flex-1 py-5 text-[11px] font-black text-zinc-500 uppercase tracking-widest hover:text-white transition-all">Cancelar</button>
                 <button onClick={handleCreatePalette} disabled={!newPaletteData.name.trim()} className="flex-[2] py-5 bg-emerald-500 hover:bg-emerald-400 disabled:opacity-30 text-black font-black uppercase rounded-2xl shadow-2xl transition-all">Criar Paleta Agora</button>
              </div>
           </div>
        </div>
      )}

      {/* Export Progress UI */}
      {isExporting && (
        <div className="fixed inset-0 z-[500] flex items-center justify-center bg-black/80 backdrop-blur-3xl animate-in fade-in">
           <div className="w-full max-w-md space-y-10 text-center px-10">
              <div className="relative inline-block">
                 <div className="absolute inset-0 blur-3xl bg-emerald-500/20 animate-pulse rounded-full" />
                 <Loader2 size={64} className="animate-spin text-emerald-500 relative mx-auto" strokeWidth={3} />
              </div>
              <div className="space-y-4">
                 <h2 className="text-2xl font-black text-white uppercase italic tracking-tighter animate-pulse">{exportStatus}</h2>
                 <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden border border-white/5">
                    <div className="h-full bg-emerald-500 transition-all duration-500" style={{ width: `${exportProgress}%` }} />
                 </div>
                 <p className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.3em]">{exportProgress}% COMPLETO</p>
              </div>
           </div>
        </div>
      )}

      {/* Save Modal */}
      {showSaveModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center p-6 bg-black/90 backdrop-blur-2xl animate-in fade-in" onClick={() => setShowSaveModal(false)}>
           <div className="w-full max-w-md bg-zinc-900 border border-white/10 rounded-[32px] p-8 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <h2 className="text-lg font-black text-white uppercase tracking-tight">Salvar Projeto</h2>
                 <button onClick={() => setShowSaveModal(false)} className="p-2 hover:bg-white/5 rounded-full transition-colors"><X size={24}/></button>
              </div>
              <div className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-zinc-500 px-1 tracking-widest">Nome do Projeto</label>
                  <input type="text" value={saveFormData.name} onChange={(e) => setSaveFormData({ ...saveFormData, name: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm text-white font-bold outline-none focus:border-emerald-500/50 transition-all" placeholder="Ex: Campanha Verão" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-zinc-500 px-1 tracking-widest">Cliente</label>
                  <input type="text" list="client-datalist" value={saveFormData.client} onChange={(e) => setSaveFormData({ ...saveFormData, client: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm text-white font-bold outline-none focus:border-emerald-500/50 transition-all" placeholder="Ex: Coca-Cola" />
                  <datalist id="client-datalist">{clients.map(c => <option key={c} value={c} />)}</datalist>
                </div>
              </div>
              <button 
                type="button"
                onClick={handleSaveProject} 
                disabled={isSyncing || !saveFormData.name.trim()} 
                className="w-full py-5 bg-emerald-500 text-black font-black uppercase rounded-2xl shadow-xl flex items-center justify-center gap-3 disabled:opacity-30 transition-all active:scale-95"
              >
                {isSyncing ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />}
                {isSyncing ? "Salvando..." : (currentProjectId ? "Atualizar Projeto" : "Salvar Projeto")}
              </button>
           </div>
        </div>
      )}

      {/* DASHBOARD VIEW */}
      {view === 'DASHBOARD' ? (
        <div className="min-h-screen w-full bg-[#050507] text-white flex flex-col overflow-y-auto custom-scrollbar">
          <header className="px-10 py-8 flex items-center justify-between border-b border-white/5 sticky top-0 bg-[#050507]/80 backdrop-blur-xl z-50">
            <div className="flex items-center gap-4">
              <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center shadow-2xl shadow-emerald-500/20"><LayoutTemplate size={20} className="text-black" /></div>
              <h1 className="text-xl font-black italic uppercase tracking-tighter">Insta<span className="text-emerald-500">Render</span></h1>
              <div className="flex items-center gap-2 px-3 py-1 bg-zinc-800 rounded-lg text-[9px] font-black uppercase text-zinc-500">
                <Database size={10} /> Local Persistence
              </div>
            </div>
            <div className="flex-1 max-w-xl mx-20 relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-600" size={18} />
              <input type="text" placeholder="Pesquisar projetos..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-white/5 border border-white/10 rounded-2xl py-3 pl-12 pr-4 text-[13px] font-bold text-white outline-none focus:border-emerald-500/50 transition-all" />
            </div>
            <button onClick={handleNewProject} className="flex items-center gap-2 px-6 py-3 bg-emerald-500 text-black font-black uppercase text-[11px] rounded-xl hover:bg-emerald-400 transition-all shadow-xl shadow-emerald-500/10 active:scale-95"><Plus size={16} strokeWidth={3} /> Criar Projeto</button>
          </header>
          <main className="p-10 max-w-[1400px] mx-auto w-full">
            <div className="mb-12 flex flex-col gap-6">
                <div className="flex items-center gap-3 text-zinc-400 mb-2">
                  <Filter size={18} className="text-emerald-500" />
                  <h2 className="text-[10px] font-black uppercase tracking-[0.2em]">Clientes</h2>
                </div>
                <div className="flex gap-2 flex-wrap">
                  <button onClick={() => setSelectedClientFilter(null)} className={`px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${!selectedClientFilter ? 'bg-emerald-500 text-black border-emerald-500 shadow-xl' : 'bg-white/5 border-white/5 text-zinc-500 hover:text-white'}`}>Todos</button>
                  {clients.map(client => (
                    <button key={client} onClick={() => setSelectedClientFilter(client)} className={`px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest border transition-all ${selectedClientFilter === client ? 'bg-emerald-500 text-black border-emerald-500 shadow-xl' : 'bg-white/5 border-white/5 text-zinc-500 hover:text-white'}`}>{client}</button>
                  ))}
                </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredProjects.map(proj => (
                  <div key={proj.id} className={`h-80 bg-zinc-900/40 border border-white/5 rounded-[32px] p-0 flex flex-col transition-all cursor-pointer group overflow-hidden ${currentProjectId === proj.id ? 'ring-2 ring-emerald-500/50' : ''}`}>

                      <div onClick={() => handleOpenProject(proj)} className="flex-1 p-8 space-y-4 hover:bg-white/5 transition-colors">
                        <div className="flex items-start justify-between">
                          <div className="w-12 h-12 bg-black/40 rounded-2xl flex items-center justify-center border border-white/5 group-hover:border-emerald-500/20"><Library size={20} className="text-zinc-600 group-hover:text-emerald-500" /></div>
                        </div>

                        <div className="space-y-3 pointer-events-none">
                          <div className="space-y-1">
                            <div className="flex items-center gap-1.5 text-emerald-500 mb-1 font-black uppercase tracking-widest text-[9px]"><UserCircle size={10} />{proj.client_name}</div>
                            <h3 className="text-base font-black text-white truncate">{proj.name}</h3>
                          </div>
                          <div className="flex flex-col gap-1.5 opacity-50">
                              <div className="flex items-center gap-2 text-[9px] font-black uppercase"><Layers size={10} /> {proj.slideCount} Slides</div>
                              <div className="flex items-center gap-2 text-[9px] font-black uppercase"><Clock size={10} /> {new Date(proj.updatedAt).toLocaleDateString()}</div>
                          </div>
                        </div>
                      </div>

                      <div className="h-16 px-6 border-t border-white/5 bg-black/20 flex items-center justify-between">
                         <button 
                            type="button"
                            onClick={(e) => handleDeleteProject(proj.id, e)}
                            className="flex items-center gap-2 py-2 px-3 rounded-xl bg-red-500/10 hover:bg-red-500 text-red-400 hover:text-white transition-all group/btn border border-red-500/10"
                            title="Excluir este projeto"
                         >
                            <Trash2 size={16} />
                            <span className="text-[9px] font-black uppercase tracking-tighter">Excluir</span>
                         </button>

                         <div className="flex items-center gap-2 text-emerald-500 opacity-40 group-hover:opacity-100 transition-opacity pointer-events-none">
                            <span className="text-[9px] font-black uppercase tracking-tighter">Abrir</span>
                            <ChevronRightSmall size={14} />
                         </div>
                      </div>
                  </div>
                ))}
            </div>
            {filteredProjects.length === 0 && !isSyncing && (
              <div className="flex flex-col items-center justify-center py-40 text-zinc-600 gap-4 opacity-50">
                 <FolderHeart size={64} strokeWidth={1} />
                 <p className="font-black uppercase tracking-widest text-[10px]">Nenhum projeto encontrado</p>
              </div>
            )}
            {isSyncing && filteredProjects.length === 0 && (
               <div className="flex flex-col items-center justify-center py-40 text-emerald-500 gap-4 opacity-50">
                 <Loader2 size={48} className="animate-spin" />
                 <p className="font-black uppercase tracking-widest text-[10px]">Carregando projetos...</p>
              </div>
            )}
          </main>
        </div>
      ) : (
        <div className="flex h-screen w-full">
          {/* EDITOR ASIDE */}
          <aside className="w-[440px] border-r border-white/5 flex flex-col bg-zinc-900/50 backdrop-blur-2xl z-20 shrink-0">
            <header className="p-5 border-b border-white/5 space-y-4">
              <div className="flex items-center justify-between">
                <button onClick={() => setView('DASHBOARD')} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-zinc-500 hover:text-white transition-all"><Home size={18} /></button>
                <div className="flex items-center gap-2 text-center flex-1 justify-center">
                  <div className="w-6 h-6 bg-emerald-500 rounded-lg flex items-center justify-center shadow-lg"><LayoutTemplate size={14} className="text-black" /></div>
                  <h1 className="text-sm font-black text-white italic uppercase tracking-tighter">InstaRender</h1>
                </div>
                <button 
                   type="button"
                   onClick={() => setShowSaveModal(true)} 
                   className={`p-2 rounded-lg transition-all ${isSyncing ? 'bg-zinc-800 text-zinc-500' : 'bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400'}`}
                   disabled={isSyncing}
                >
                  {isSyncing ? <Loader2 size={18} className="animate-spin" /> : <Save size={18} />}
                </button>
              </div>
              <nav className="flex gap-1 p-1 bg-black/40 rounded-xl">
                {['TEMPLATES', 'DESIGN', 'ASSETS', 'TEXTURES', 'JSON'].map(tab => (
                  <button key={tab} onClick={() => setActiveTab(tab as any)} className={`flex-1 flex flex-col items-center justify-center gap-1 py-2 px-1 rounded-lg text-[9px] font-black uppercase tracking-wider transition-all ${activeTab === tab ? 'bg-zinc-800 text-emerald-400 border border-white/5' : 'text-zinc-500 hover:text-zinc-300'}`}>
                    {tab === 'TEMPLATES' && <Library size={14} />}
                    {tab === 'DESIGN' && <Palette size={14} />}
                    {tab === 'ASSETS' && <ImageIcon size={14} />}
                    {tab === 'TEXTURES' && <Layers size={14} />}
                    {tab === 'JSON' && <FileJson size={14} />}
                    {tab.slice(0, 4)}
                  </button>
                ))}
              </nav>
            </header>
            <div className="flex-1 overflow-y-auto custom-scrollbar p-5 space-y-6">
              {activeTab === 'DESIGN' ? (
                <div className="space-y-10 animate-in fade-in slide-in-from-left-4 duration-300">
                  <section className="space-y-4">
                    <div className="flex items-center justify-between px-1">
                      <h3 className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Brand Palettes</h3>
                      <button onClick={() => setIsCreatingPalette(true)} className="text-[8px] font-black text-emerald-400 uppercase flex items-center gap-1 hover:text-white transition-all bg-emerald-500/10 px-2.5 py-1.5 rounded-lg border border-emerald-500/20"><Plus size={10} strokeWidth={3} /> New Palette</button>
                    </div>
                    <div className="grid grid-cols-1 gap-3 max-h-[300px] overflow-y-auto custom-scrollbar pr-2">
                      {brandPresets.map(preset => (
                        <button key={preset.id} onClick={() => handleApplyPalettePreset(preset)} className={`w-full p-4 border rounded-2xl transition-all flex items-center justify-between group ${activePaletteId === preset.id ? 'bg-emerald-500/10 border-emerald-500' : 'bg-white/5 border-white/5 hover:border-white/10'}`}>
                          <div className="flex items-center gap-4">
                            <div className="flex -space-x-2">{preset.colors.slice(0, 4).map((c: string, i: number) => (<div key={i} className="w-5 h-5 rounded-full border-2 border-zinc-900 shadow-sm" style={{ backgroundColor: c }} />))}</div>
                            <span className={`text-[11px] font-black uppercase ${activePaletteId === preset.id ? 'text-emerald-400' : 'text-zinc-400'}`}>{preset.name}</span>
                          </div>
                          {!DEFAULT_BRAND_PRESETS.some(d => d.id === preset.id) && (<button onClick={(e) => handleDeletePalette(e, preset.id)} className="p-2 opacity-0 group-hover:opacity-100 hover:text-red-400 transition-all text-zinc-600"><Trash2 size={12} /></button>)}
                        </button>
                      ))}
                    </div>
                  </section>

                  <section className="space-y-6 border-t border-white/5 pt-6">
                    <div className="flex items-center gap-2 px-1 pb-2"><Trello size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Layout & Spacing</h3></div>
                    <div className="space-y-8">
                       <TransformControl label="Proximidade (Block Gap)" value={currentSlide?.options?.blockGap ?? 16} min={0} max={160} step={2} onChange={(v) => updateSlideProperty(['options', 'blockGap'], v)} />
                       <TransformControl label="Distância (Section Gap)" value={currentSlide?.options?.sectionGap ?? 48} min={0} max={300} step={4} onChange={(v) => updateSlideProperty(['options', 'sectionGap'], v)} />
                       <TransformControl label="Margens (Padding)" value={currentSlide?.options?.padding ?? 80} min={20} max={200} step={4} onChange={(v) => updateSlideProperty(['options', 'padding'], v)} />
                    </div>
                  </section>

                  <section className="space-y-6">
                    <div className="flex items-center gap-2 px-1 border-b border-white/5 pb-2"><Edit3 size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Editor de Cores</h3></div>
                    <div className="grid grid-cols-1 gap-8">
                      <PaletteColorSelector label="Background" value={currentSlide?.options?.background || '#0D0D0D'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'background'], v)} />
                      <PaletteColorSelector label="Accent" value={currentSlide?.options?.accent || '#EAB308'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'accent'], v)} />
                      <PaletteColorSelector label="Text" value={currentSlide?.options?.text || '#FFFFFF'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'text'], v)} />

                      <div className="space-y-4 pt-4 border-t border-white/5">
                        <PaletteColorSelector label="Cards & Boxes BG" value={currentSlide?.options?.cardBg || currentSlide?.options?.accent || '#EAB308'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'cardBg'], v)} />
                        <PaletteColorSelector label="Cards & Boxes TEXT" value={currentSlide?.options?.cardTextColor || '#000000'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'cardTextColor'], v)} />
                        <TransformControl label="Opacidade dos Cards/Boxes" value={currentSlide?.options?.cardOpacity !== undefined ? currentSlide.options.cardOpacity : 1} min={0} max={1} step={0.01} onChange={(v) => updateSlideProperty(['options', 'cardOpacity'], v)} />
                      </div>

                      <div className="space-y-4 pt-4 border-t border-white/5">
                        <PaletteColorSelector label="Highlight [[...]] BG" value={currentSlide?.options?.hlBgColor || currentSlide?.options?.accent || '#EAB308'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'hlBgColor'], v)} />
                        <PaletteColorSelector label="Highlight [[...]] TEXT" value={currentSlide?.options?.hlTextColor || '#000000'} palette={currentPalette} onChange={(v) => updateSlideProperty(['options', 'hlTextColor'], v)} />
                      </div>
                    </div>
                  </section>
                </div>
              ) : activeTab === 'TEMPLATES' ? (
                <div className="grid grid-cols-1 gap-2.5 animate-in fade-in duration-300">
                   {templates.map(tpl => (
                      <button 
                        key={tpl.name} 
                        onClick={() => handleTemplateSelect(tpl)} 
                        className={`w-full p-4 text-left border rounded-xl transition-all flex items-center justify-between group ${currentSlide?.template === tpl.name ? 'border-emerald-500 bg-emerald-500/10 shadow-[0_0_20px_rgba(16,185,129,0.1)]' : 'border-white/5 bg-white/5 hover:border-emerald-500/20'}`}
                      >
                        <div className="flex items-center gap-4">
                           <div className={`w-12 h-12 rounded-xl flex items-center justify-center border transition-all ${currentSlide?.template === tpl.name ? 'bg-emerald-500 border-emerald-500 shadow-[0_0_20px_rgba(16,185,129,0.3)]' : 'bg-black border-white/5 group-hover:border-white/20'}`}>
                              <Library size={20} className={currentSlide?.template === tpl.name ? 'text-black' : 'text-zinc-500'} />
                           </div>
                           <div>
                              <p className={`text-[10px] font-black uppercase mb-0.5 tracking-tighter ${currentSlide?.template === tpl.name ? 'text-emerald-400' : 'text-white'}`}>{tpl.name.replace(/_/g, ' ')}</p>
                              <p className="text-[9px] text-zinc-500 opacity-60 font-medium">{tpl.description}</p>
                           </div>
                        </div>
                        {currentSlide?.template === tpl.name && <Check className="text-emerald-500" size={16} />}
                      </button>
                    ))}
                </div>
              ) : activeTab === 'TEXTURES' ? (
                <div className="space-y-10 animate-in fade-in slide-in-from-left-4 duration-300">
                   <section className="space-y-4">
                      <div className="flex items-center gap-2 px-1 border-b border-white/5 pb-2"><Layers size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Tipo de Ruído</h3></div>
                      <div className="grid grid-cols-2 gap-2">
                        {TEXTURE_PRESETS.map(preset => (
                          <button key={preset.id} onClick={() => updateSlideProperty(['options', 'texture', 'type'], preset.id)} className={`flex flex-col items-center gap-2 p-4 rounded-2xl border transition-all ${currentSlide?.options?.texture?.type === preset.id ? 'bg-emerald-500/10 border-emerald-500 text-emerald-400' : 'bg-white/5 border-white/5 text-zinc-500 hover:text-zinc-300'}`}><preset.icon size={20} /><span className="text-[9px] font-black uppercase tracking-widest">{preset.label}</span></button>
                        ))}
                      </div>
                   </section>
                   <section className="space-y-6">
                      <div className="flex items-center gap-2 px-1 border-b border-white/5 pb-2"><Wind size={14} className="text-zinc-600" /><h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Ajustes de Textura</h3></div>
                      <div className="space-y-8">
                        <TransformControl label="Intensidade (Opacidade)" value={currentSlide?.options?.texture?.amount ?? 0} min={0} max={1} step={0.01} onChange={(v) => updateSlideProperty(['options', 'texture', 'amount'], v)} />
                        <div className="space-y-2.5">
                           <span className="text-[9px] font-black text-zinc-500 uppercase px-1 tracking-widest">Modo de Camada (Blend)</span>
                           <div className="grid grid-cols-2 gap-1.5 max-h-[200px] overflow-y-auto custom-scrollbar pr-1">{BLEND_MODES.map(mode => (<button key={mode} onClick={() => updateSlideProperty(['options', 'texture', 'blendMode'], mode)} className={`py-2 px-3 rounded-lg text-left text-[9px] font-black uppercase tracking-tighter border transition-all ${currentSlide?.options?.texture?.blendMode === mode ? 'bg-emerald-500 text-black border-emerald-500' : 'bg-black/40 border-white/5 text-zinc-500 hover:text-white'}`}>{mode}</button>))}</div>
                        </div>
                      </div>
                   </section>
                </div>
              ) : activeTab === 'ASSETS' ? (
                <div className="space-y-8 animate-in fade-in duration-300">
                  <div className={`p-6 border rounded-[32px] transition-all ${isLocked ? 'opacity-50 pointer-events-none' : 'bg-white/5 border-white/10'}`}>
                    {imageConfig?.url ? (
                      <div className="space-y-10">
                        <div className="relative aspect-video rounded-2xl overflow-hidden bg-zinc-950 border border-white/5 group shadow-inner">
                          <img src={imageConfig.url} className="w-full h-full object-contain" />
                          <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                              <button onClick={() => updateSlideProperty(['image', 'url'], undefined)} className="p-3 bg-red-500 text-white rounded-xl shadow-xl hover:scale-110 transition-transform"><Trash2 size={20}/></button>
                          </div>
                        </div>

                        <div className="space-y-4">
                           <span className="text-[9px] font-black uppercase text-zinc-500 px-1 tracking-widest">Layout de Imagem</span>
                           <div className="grid grid-cols-5 gap-2">
                              {IMAGE_TYPE_PRESETS.map(preset => (
                                <button 
                                  key={preset.id} 
                                  onClick={() => updateSlideProperty(['image', 'type'], preset.id)}
                                  className={`flex flex-col items-center gap-2 p-2 rounded-xl border transition-all ${imageConfig.type === preset.id ? 'bg-emerald-500 border-emerald-500 text-black shadow-lg' : 'bg-black/40 border-white/5 text-zinc-500 hover:text-white'}`}
                                  title={preset.label}
                                >
                                  <preset.icon size={16} />
                                </button>
                              ))}
                           </div>
                        </div>

                        {(imageConfig.type === 'IMAGE_BOX' || imageConfig.type === 'FOCUS_SUBJECT' || imageConfig.type === 'IMAGE_SPLIT_HALF') && (
                           <div className="space-y-4">
                              <span className="text-[9px] font-black uppercase text-zinc-500 px-1 tracking-widest">Posição e Orientação</span>
                              <div className="flex gap-2">
                                 <button 
                                    onClick={() => updateSlideProperty(['image', 'position'], imageConfig.position === 'left' ? 'right' : 'left')}
                                    className="flex-1 py-4 bg-zinc-800 rounded-2xl border border-white/5 flex flex-col items-center gap-2 hover:bg-zinc-700 transition-all group"
                                 >
                                    <div className="flex items-center gap-3">
                                       <AlignLeft size={16} className={imageConfig.position === 'left' ? 'text-emerald-400' : 'text-zinc-600'} />
                                       <div className="w-4 h-2 bg-zinc-600 rounded-full relative overflow-hidden">
                                          <div className={`absolute inset-y-0 w-1/2 bg-emerald-500 transition-all ${imageConfig.position === 'left' ? 'left-0' : 'left-1/2'}`} />
                                       </div>
                                       <AlignRight size={16} className={imageConfig.position === 'right' ? 'text-emerald-400' : 'text-zinc-600'} />
                                    </div>
                                    <span className="text-[8px] font-black uppercase tracking-tighter text-zinc-500 group-hover:text-zinc-300">Posição Lateral</span>
                                 </button>

                                 {imageConfig.type === 'IMAGE_SPLIT_HALF' && (
                                    <button 
                                       onClick={() => updateSlideProperty(['image', 'position'], (imageConfig.position === 'top' || imageConfig.position === 'bottom') ? 'right' : 'top')}
                                       className="flex-1 py-4 bg-zinc-800 rounded-2xl border border-white/5 flex flex-col items-center gap-2 hover:bg-zinc-700 transition-all group"
                                    >
                                       <div className="flex items-center gap-3">
                                          <MoveVertical size={16} className={(imageConfig.position === 'top' || imageConfig.position === 'bottom') ? 'text-emerald-400' : 'text-zinc-600'} />
                                          <div className="w-4 h-2 bg-zinc-600 rounded-full relative overflow-hidden">
                                             <div className={`absolute inset-y-0 w-1/2 bg-emerald-500 transition-all ${(imageConfig.position === 'top' || imageConfig.position === 'bottom') ? 'left-1/2' : 'left-0'}`} />
                                          </div>
                                          <MoveHorizontal size={16} className={(imageConfig.position === 'left' || imageConfig.position === 'right') ? 'text-emerald-400' : 'text-zinc-600'} />
                                       </div>
                                       <span className="text-[8px] font-black uppercase tracking-tighter text-zinc-500 group-hover:text-zinc-300">Eixo V / H</span>
                                    </button>
                                 )}
                              </div>
                           </div>
                        )}

                        <div className="space-y-6">
                          <div className="flex gap-4">
                            <TransformControl label="Escala" value={imageConfig.scale ?? 1} min={0.1} max={5} step={0.05} onChange={(v) => updateSlideProperty(['image', 'scale'], v)} />
                            {imageConfig.type === 'IMAGE_BOX' && <TransformControl label="Largura Box" value={imageConfig.width ?? 480} min={200} max={1000} step={10} onChange={(v) => updateSlideProperty(['image', 'width'], v)} />}
                          </div>

                          <div className="flex gap-4">
                             <TransformControl label="Offset X" value={imageConfig.x ?? 0} min={-1000} max={1000} step={1} onChange={(v) => updateSlideProperty(['image', 'x'], v)} />
                             <TransformControl label="Offset Y" value={imageConfig.y ?? 0} min={-1000} max={1000} step={1} onChange={(v) => updateSlideProperty(['image', 'y'], v)} />
                          </div>

                          <TransformControl label="Opacidade do Fundo" value={imageConfig.backgroundOpacity ?? 1} min={0} max={1} step={0.05} onChange={(v) => updateSlideProperty(['image', 'backgroundOpacity'], v)} />
                        </div>
                      </div>
                    ) : (
                      <div className="flex flex-col items-center justify-center h-48 border-2 border-dashed border-white/5 rounded-[40px] hover:bg-white/5 transition-all relative group cursor-pointer">
                        <PlusCircle className="w-10 h-10 text-zinc-800 mb-4 group-hover:text-emerald-500 transition-colors" /><p className="text-[10px] font-black uppercase text-zinc-600 group-hover:text-zinc-400">Arraste ou clique para Upload</p><input type="file" className="absolute inset-0 opacity-0 cursor-pointer" accept="image/*" onChange={handleImageUpload} disabled={isLocked} />
                      </div>
                    )}
                  </div>
                  <div className="px-1 py-4 bg-zinc-800/20 border border-zinc-700/30 rounded-2xl flex flex-col items-center gap-3"><ClipboardPaste size={20} className="text-zinc-600" /><p className="text-[10px] font-black uppercase text-zinc-500 text-center px-4">Use CTRL+V no editor para colar imagens rapidamente!</p></div>
                </div>
              ) : activeTab === 'JSON' ? (
                <textarea value={dslInput} onChange={(e) => setDslInput(e.target.value)} className="w-full h-[500px] bg-black/40 p-4 font-mono text-[10px] border border-white/5 rounded-xl outline-none" spellCheck={false} />
              ) : null}
            </div>
            <footer className="p-5 border-t border-white/5 bg-zinc-950 flex gap-3">
              <button disabled={!carousel || isExporting} onClick={() => { setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i))); setShowExportModal(true); }} className="flex-1 py-4 bg-emerald-500 hover:bg-emerald-400 disabled:opacity-30 text-black font-black rounded-xl text-[10px] uppercase transition-all shadow-lg flex items-center justify-center gap-3 active:scale-95"><Download size={16} strokeWidth={3} /> Exportar</button>
            </footer>
          </aside>

          {/* CANVAS AREA */}
          <main className="flex-1 bg-[#18181b] relative flex flex-col">
            {error && <div className="absolute top-5 left-1/2 -translate-x-1/2 z-[100] bg-red-500 text-white px-6 py-3 rounded-2xl flex items-center gap-3 shadow-2xl animate-in slide-in-from-top-4 duration-300"><AlertCircle size={18}/><span className="text-[11px] font-black uppercase">{error}</span></div>}
            <div className="absolute top-5 right-5 z-40 flex items-center gap-0.5 bg-black/30 backdrop-blur-xl p-1 rounded-xl border border-white/5 opacity-60 hover:opacity-100 transition-opacity">
              <button onClick={() => setZoom(Math.max(0.1, zoom - 0.05))} className="p-2 text-zinc-500 hover:text-white transition-all"><ZoomOut size={16} /></button>
              <div className="px-2 text-[9px] font-black font-mono text-zinc-400 w-10 text-center">{(zoom * 100).toFixed(0)}%</div>
              <button onClick={() => setZoom(Math.min(1.5, zoom + 0.05))} className="p-2 text-zinc-500 hover:text-white transition-all"><ZoomIn size={16} /></button>
            </div>
            <div className="flex-1 flex items-center justify-center relative overflow-auto custom-scrollbar p-10" onMouseUp={handleCanvasMouseUp}>
              <div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="transition-transform duration-500 shadow-[0_60px_150px_rgba(0,0,0,0.8)] shrink-0">
                {carousel?.slides?.[currentIndex] ? <SlideCanvas slide={carousel.slides[currentIndex]} index={currentIndex} canvasRef={canvasRef} onEditIcon={(block, blockIdx) => setEditingIconBlock({ block, index: blockIdx })} /> : <div className="opacity-10"><Loader2 className="w-10 h-10 animate-spin text-emerald-500" /></div>}
              </div>
            </div>
            {carousel && carousel.slides.length > 0 && (
              <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-40 flex items-center gap-8 bg-black/40 backdrop-blur-xl px-8 py-4 rounded-[32px] border border-white/5 shadow-2xl transition-opacity hover:opacity-100 opacity-90">
                 <button disabled={currentIndex === 0} onClick={() => setCurrentIndex(prev => prev - 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronLeft size={20} strokeWidth={3}/></button>
                 <div className="flex gap-2.5">{carousel.slides.map((_, i) => (<button key={i} onClick={() => setCurrentIndex(i)} className={`h-2 transition-all duration-300 rounded-full ${currentIndex === i ? 'w-8 bg-emerald-500 shadow-lg shadow-emerald-500/30' : 'w-2 bg-white/10 hover:bg-white/20'}`} />))}</div>
                 <button disabled={currentIndex === carousel.slides.length - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronRight size={20} strokeWidth={3}/></button>
              </div>
            )}
          </main>
        </div>
      )}
    </div>
  );
};

export default App;

export type BlockType = 'TITLE' | 'LIST' | 'IMAGE' | 'SPACER' | 'PARAGRAPH' | 'CARD' | 'BADGE' | 'BOX';

export interface Block {
  type: BlockType;
  content?: string | string[];
  options?: {
    highlight?: string;
    variant?: 'default' | 'accent' | 'muted' | 'box' | 'ghost' | 'outlined';
    size?: 'sm' | 'md' | 'lg';
    icon?: string;
    customIcon?: string; // URL da imagem ou string SVG
    align?: 'left' | 'center' | 'right';
    // Text styling overrides
    fontSize?: number;
    color?: string;
    letterSpacing?: number;
    lineHeight?: number;
    textAlign?: 'left' | 'center' | 'right';
  };
}

export interface Project {
  id: string;
  name: string;
  client_name: string; // Adicionado para suporte ao Supabase
  updatedAt: number;
  data: string; // JSON string do carrossel
  slideCount: number;
}

export type LayoutType = 'CENTERED' | 'STACKED' | 'SPLIT_IMAGE_TOP' | 'SPLIT_IMAGE_SIDE' | 'EDITORIAL' | 'GRID';

export interface TemplateDefinition {
  name: string;
  description: string;
  layoutType: LayoutType;
  allowedBlocks: BlockType[];
  maxBlocks?: number;
}

export interface SlideImageConfig {
  type: 'IMAGE_SELECT' | 'IMAGE_BACKGROUND' | 'IMAGE_BOX' | 'FOCUS_SUBJECT' | 'IMAGE_GLASS_CARD' | 'IMAGE_SPLIT_HALF' | 'NONE';
  url?: string;
  overlay?: 'dark' | 'blur-card' | 'none';
  boxOverlay?: 'dark' | 'light';
  // Fix: Expanded position type to support vertical layouts
  position?: 'right' | 'left' | 'top' | 'bottom';
  format?: 'png' | 'jpg';
  scale?: number;
  x?: number;
  y?: number;
  width?: number;
